}

# Ruta del log
$LogPath = "C:\Windows\Setup\Scripts\WinRE_$(Get-Date -Format 'yyyyMMdd_HHmmss').log"

# Función para registrar mensajes
function Write-Log {
    param (
        [string]$Message,
        [string]$Level = "INFO",
        [ConsoleColor]$Color = [ConsoleColor]::White
    )
    $timestamp = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss")
    $logMessage = "[$timestamp] [$Level] $Message"

    # Mostrar en consola con color
    Write-Host $logMessage -ForegroundColor $Color

    # Escribir en archivo de log
    Add-Content -Path $LogPath -Value $logMessage
}

Write-Log "==== INICIO DEL SCRIPT ====" "INFO" Cyan

# Desactivar WinRE temporalmente
Write-Log "Desactivando WinRE..." "INFO" Yellow
try {
    reagentc /disable 2>&1 | Out-Null
    Write-Log "WinRE deshabilitado correctamente o ya estaba deshabilitado." "INFO" Green
} catch {
    Write-Log "Advertencia: no se pudo deshabilitar WinRE, continuando..." "WARN" Yellow
}

# =========================
# Detectar partición de recuperación (UEFI o Legacy)
# =========================
$recoveryPartition = Get-Partition | Where-Object {
    # UEFI estándar
    ($_.GptType -eq '{DE94BBA4-06D1-4D40-A16A-BFD50179D6AC}') -or
    # Legacy: NTFS oculta de tamaño entre 300MB y 1GB
    ($_.Size -ge 300MB -and $_.Size -le 1GB -and $_.Type -eq 'Unknown')
} | Select-Object -First 1

if (-not $recoveryPartition) {
    Write-Log "ERROR: No se detectó una partición de recuperación compatible." "ERROR" Red
    Write-Log "==== FIN DEL SCRIPT ====" "INFO" Cyan
    exit 1
}

$disk = $recoveryPartition.DiskNumber
$part = $recoveryPartition.PartitionNumber
Write-Log "Partición de recuperación detectada: Disco $disk, Partición $part" "INFO" Cyan

# =========================
# Asignar letra temporal si no tiene
# =========================
if ($recoveryPartition.DriveLetter) {
    $mountLetter = $recoveryPartition.DriveLetter
    Write-Log "Partición ya tiene letra: $mountLetter" "INFO" Cyan
} else {
    $usedLetters = (Get-Volume).DriveLetter
    $mountLetter = 'R'
    while ($usedLetters -contains $mountLetter) {
        $mountLetter = [char]([int][char]$mountLetter + 1)
    }

    Write-Log "Asignando letra temporal $mountLetter a la partición Recovery..." "INFO" Yellow
    try {
        $recoveryPartition | Set-Partition -NewDriveLetter $mountLetter
    } catch {
        Write-Log "ERROR: No se pudo asignar la letra $mountLetter a la partición." "ERROR" Red
        exit 1
    }

    # Esperar un poco para que la unidad esté disponible
    Start-Sleep -Seconds 3
    if (-not (Test-Path "$mountLetter`:")) {
        Write-Log "ERROR: La unidad $mountLetter no se montó correctamente después de asignarla." "ERROR" Red
        exit 1
    }
}

$recoveryPath = "$mountLetter`:\Recovery\WindowsRE"

# Crear carpeta si no existe
if (!(Test-Path $recoveryPath)) {
    Write-Log "Creando carpeta $recoveryPath..." "INFO" Yellow
    New-Item -ItemType Directory -Path $recoveryPath -Force | Out-Null
} else {
    Write-Log "Carpeta $recoveryPath ya existe." "INFO" Cyan
}

# =========================
# Reemplazar WinRE con el nuevo
# =========================
$newWinRE = "C:\Recovery\OEM\C\Windows\System32\Recovery\winre.wim"
if (Test-Path $newWinRE) {
    Write-Log "Preparando carpeta $recoveryPath para copiar WinRE..." "INFO" Yellow

	# =========================
	# Tomar posesión de la carpeta WinRE y eliminar winre.wim anterior
	# =========================
	Write-Log "Tomando posesión de $recoveryPath y su contenido..." "INFO" Yellow

	try {
		# Asegurar que la carpeta existe antes de tomar posesión
		if (!(Test-Path $recoveryPath)) {
			Write-Log "La carpeta $recoveryPath no existe, creando..." "INFO" Yellow
			New-Item -ItemType Directory -Path $recoveryPath -Force | Out-Null
		}

		# Tomar propiedad de la carpeta y su contenido
		takeown /F "$recoveryPath" /R /A | Out-Null

		# Conceder control total a administradores
		icacls "$recoveryPath" /grant Administradores:F /T /C | Out-Null

		Write-Log "Propiedad y permisos actualizados correctamente en $recoveryPath." "INFO" Green

		# Eliminar el archivo winre.wim anterior si existe
		$oldWinRE = Join-Path $recoveryPath "winre.wim"
		if (Test-Path $oldWinRE) {
			Write-Log "Eliminando winre.wim anterior..." "INFO" Yellow
			Remove-Item -Path $oldWinRE -Force
			Write-Log "Archivo winre.wim anterior eliminado correctamente." "INFO" Green
		} else {
			Write-Log "No se encontró winre.wim anterior, continuando..." "INFO" Cyan
		}
	} catch {
		Write-Log "ERROR: No se pudo tomar posesión o eliminar winre.wim anterior en $recoveryPath" "ERROR" Red
		exit 1
	}

    # Copiar WinRE directamente
try {
    Copy-Item $newWinRE -Destination "$recoveryPath\winre.wim" -Force
    Write-Log "WinRE personalizado copiado correctamente a $recoveryPath" "INFO" Green
} catch {
    Write-Log "ERROR: No se pudo copiar WinRE a $recoveryPath. Ejecuta el script como administrador o verifica que la partición no esté protegida." "ERROR" Red
    exit 1
}


