# Script para restaurar Recovery
# -------------------------------

# Ruta de destino en el sistema
$destinationPath = "C:\Recovery"

# Crear carpeta de destino si no existe
if (-not (Test-Path $destinationPath)) {
    New-Item -ItemType Directory -Path $destinationPath -Force | Out-Null
    Write-Host "Se creó la carpeta de destino: $destinationPath"
}

# Obtener todas las unidades
$drives = Get-PSDrive -PSProvider FileSystem

foreach ($drive in $drives) {

    # Construir ruta literal en la unidad
    $sourcePath = Join-Path $drive.Root 'Sources\$OEM$\$1\Recovery'

    if (Test-Path $sourcePath) {
        Write-Host "Se encontró Recovery en: $sourcePath"

        # Copiar archivo por archivo
        Get-ChildItem -Path $sourcePath -Recurse | ForEach-Object {
            $relativePath = $_.FullName.Substring($sourcePath.Length).TrimStart('\')
            $dest = Join-Path $destinationPath $relativePath

            # Crear carpeta si no existe
            $destDir = Split-Path $dest
            if (-not (Test-Path $destDir)) {
                New-Item -ItemType Directory -Path $destDir -Force | Out-Null
            }

            # Copiar archivo
            try {
                Copy-Item -Path $_.FullName -Destination $dest -Force -ErrorAction Stop
                Write-Host "Copiado: $($_.FullName) -> $dest"
            } catch {
                Write-Warning "No se pudo copiar: $($_.FullName)"
            }
        }

        Write-Host "Copia completada desde: $sourcePath"

        # -------------------------------
        # Restaurar atributos de carpeta
        # -------------------------------
        try {
            # Carpeta principal
            attrib +h +s $destinationPath
            Write-Host "Atributos restaurados para $destinationPath (Hidden y System)"

            # Subcarpetas y archivos
            Get-ChildItem -Path $destinationPath -Recurse | ForEach-Object {
                attrib +h +s $_.FullName
            }
            Write-Host "Atributos aplicados a todos los archivos y subcarpetas"
        } catch {
            Write-Warning "No se pudieron aplicar atributos: $_"
        }

        break
    } else {
        Write-Host "No se encontró Recovery en: $($drive.Root)"
    }
}

